+    #[tokio::test]
+    async fn reindex_complete_callback_on_empty_range() {
+        let dir = tempdir().unwrap();
+        let scfg = test_storage_config(dir.path());
+        let storage = AppendLogRecorderStorage::open(scfg.clone()).unwrap();
